import styled from "styled-components"

import brandIcon from '../img/LandingPage/brandLogo.svg'

const LandingPage = () => {
  return (
    <Container>
      <Brand>
        <img src={brandIcon} alt="brandIcon" />
        <span> Adam Jałocha </span>
        <span> Web developer </span>
      </Brand>
      <Introduction> Adam Jałocha </Introduction>
      <More> More </More>

      <QuickContact> QuickContact </QuickContact>
    </Container>
  )
}

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: auto 1fr auto / 1fr auto;
  align-items: center;

  font-family: Rubik;
  font-weight: 600;

  & > * {
    padding: 1em;
  }
`

const Brand = styled.span`
  display: grid;
  grid-template: 1fr 1fr / auto 1fr;
  column-gap: 0.5em;

  & img {
    grid-column: 1;
    grid-row: 1/3;
    height: 100%;
    width: auto;
  }

  & span {
    font-weight: 400;
    font-size: 0.8em;
  }
`

const Introduction = styled.span``
const More = styled.span``
const QuickContact = styled.div`
  grid-column: 2;
  grid-row: 1/4;
`

export default LandingPage
